    pub(crate) fn signature_has_rest_parameter(&self, signature: SignatureHandle) -> bool {
        self.signature_record(signature).flags & SIGNATURE_FLAGS_HAS_REST_PARAMETER != 0
    }

    pub(crate) fn signature_has_literal_types(&self, signature: SignatureHandle) -> bool {
        self.signature_record(signature).flags & SIGNATURE_FLAGS_HAS_LITERAL_TYPES != 0
    }

    pub(crate) fn is_fresh_literal_type(&self, t: TypeHandle) -> bool {
        self.type_flags(t) & TYPE_FLAGS_FRESHABLE != 0
            && self.type_record(t).as_literal_type().fresh_type == Some(t)
    }

    pub(crate) fn get_string_literal_value(&self, t: TypeHandle) -> String {
        self.get_string_literal_value_ref(t).to_string()
    }

    pub(crate) fn get_string_literal_value_ref(&self, t: TypeHandle) -> &str {
        self.type_record(t).as_literal_type().value.as_string()
    }

    pub(crate) fn get_number_literal_value(&self, t: TypeHandle) -> Number {
        self.type_record(t).as_literal_type().value.as_number()
    }

    pub(crate) fn get_big_int_literal_value(&self, t: TypeHandle) -> PseudoBigInt {
        self.type_record(t).as_literal_type().value.as_big_int()
    }

    pub(crate) fn get_boolean_literal_value(&self, t: TypeHandle) -> bool {
        self.type_record(t).as_literal_type().value.as_bool()
    }

    pub(crate) fn is_mutable_tuple_type(&self, t: TypeHandle) -> bool {
        self.is_tuple_type(t) && !self.target_tuple_type_record(t).readonly
    }

    pub(crate) fn is_generic_tuple_type_handle(&self, t: TypeHandle) -> bool {
        self.is_tuple_type(t)
            && self.target_tuple_type_record(t).combined_flags & ELEMENT_FLAGS_VARIADIC != 0
    }

    pub(crate) fn is_single_element_generic_tuple_type(&self, t: TypeHandle) -> bool {
        self.is_generic_tuple_type_handle(t)
            && self.target_tuple_type_record(t).element_infos.len() == 1
    }

    pub(crate) fn is_unit_type(&self, t: TypeHandle) -> bool {
        self.type_flags(t) & TYPE_FLAGS_UNIT != 0
    }

    pub(crate) fn is_neither_unit_type_nor_never(&self, t: TypeHandle) -> bool {
        self.type_flags(t) & (TYPE_FLAGS_UNIT | TYPE_FLAGS_NEVER) == 0
    }

    pub(crate) fn is_literal_type(&self, t: TypeHandle) -> bool {
        let flags = self.type_flags(t);
        if flags & TYPE_FLAGS_BOOLEAN != 0 {
            return true;
        }
        if flags & TYPE_FLAGS_UNION != 0 {
            if flags & TYPE_FLAGS_ENUM_LITERAL != 0 {
                return true;
            }
            return self
                .type_types_slice(t)
                .iter()
                .all(|t| self.is_unit_type(*t));
        }
        self.is_unit_type(t)
    }

    pub(crate) fn is_type_usable_as_property_name(&self, t: TypeHandle) -> bool {
        self.type_flags(t) & TYPE_FLAGS_STRING_OR_NUMBER_LITERAL_OR_UNIQUE != 0
    }

    pub(crate) fn get_property_name_from_type(&self, t: TypeHandle) -> String {
        let flags = self.type_flags(t);
        if flags & TYPE_FLAGS_STRING_LITERAL != 0 {
            return any_string(&self.type_record(t).as_literal_type().value);
        }
        if flags & TYPE_FLAGS_NUMBER_LITERAL != 0 {
            return any_number(&self.type_record(t).as_literal_type().value).to_string();
        }
        if flags & TYPE_FLAGS_UNIQUE_ES_SYMBOL != 0 {
            return self.type_record(t).as_unique_es_symbol_type().name.clone();
        }
        panic!("Unhandled case in getPropertyNameFromType");
    }

