    pub(crate) fn node_fallthrough_flow_node(&self, node: ast::Node) -> Option<ast::FlowRef> {
        let state = self.node_binding_state(node);
        state.fallthrough_flow_node(node)
    }

    pub(crate) fn output_node_flow_node(&self, node: ast::Node) -> Option<ast::FlowRef> {
        if let Some(state) = self.try_node_binding_state(node) {
            return state.flow_node(node);
        }
        self.checker_synthetic_flow_nodes.get(&node).copied()
    }

    pub(crate) fn record_checker_synthetic_flow_node(
        &mut self,
        node: ast::Node,
        flow_node: Option<ast::FlowRef>,
    ) {
        if let Some(flow_node) = flow_node {
            self.checker_synthetic_flow_nodes.insert(node, flow_node);
        } else {
            self.checker_synthetic_flow_nodes.remove(&node);
        }
    }

