    fn is_unchecked_js_suggestion_handle(
        &self,
        node: ast::Node,
        suggestion: Option<ast::SymbolHandle>,
        exclude_classes: bool,
    ) -> bool {
        let store = self.store_for_node(node);
        let file = ast::get_source_file_of_node(store, Some(node));
        let Some(file) = file else {
            return false;
        };
        let file_data = store.as_source_file(file);
        if !self.compiler_options.check_js.is_unknown()
            || file_data.check_js_directive().is_some()
            || !(file_data.script_kind() == core::ScriptKind::JS
                || file_data.script_kind() == core::ScriptKind::JSX)
        {
            return false;
        }

        let mut declaration_file = None;
        if let Some(suggestion) = suggestion {
            if let Some(first_declaration) = self.first_symbol_handle_declaration(suggestion) {
                let declaration_store = self.store_for_node(first_declaration);
                declaration_file =
                    ast::get_source_file_of_node(declaration_store, Some(first_declaration));
            }
        }

        let value_declaration =
            suggestion.and_then(|suggestion| self.symbol_handle_value_declaration(suggestion));
        let suggestion_has_no_extends_or_decorators = suggestion.is_none()
            || value_declaration.is_none()
            || !ast::is_class_like(
                self.store_for_node(value_declaration.unwrap()),
                value_declaration.unwrap(),
            )
            || !ast::get_extends_heritage_clause_elements(
                self.store_for_node(value_declaration.unwrap()),
                value_declaration.unwrap(),
            )
            .is_empty()
            || ast::class_or_constructor_parameter_is_decorated(
                self.store_for_node(value_declaration.unwrap()),
                false,
                value_declaration.unwrap(),
            );
        let declaration_file_is_different =
            declaration_file.as_ref().is_some_and(|declaration_file| {
                self.store_for_node(*declaration_file)
                    .as_source_file(*declaration_file)
                    .path()
                    != file_data.path()
            });
        let declaration_file_is_global = declaration_file.as_ref().is_some_and(|file| {
            ast::is_global_source_file(&self.store_for_node(*file).source_file_view(*file))
        });
        !(declaration_file_is_different && declaration_file_is_global)
            && !(exclude_classes
                && suggestion.is_some()
                && self
                    .symbol_handle_flags(suggestion.unwrap())
                    .intersects(ast::SYMBOL_FLAGS_CLASS)
                && suggestion_has_no_extends_or_decorators)
            && !(exclude_classes
                && ast::is_property_access_expression(store, node)
                && store
                    .expression(node)
                    .is_some_and(|expression| store.kind(expression) == ast::Kind::ThisKeyword)
                && suggestion_has_no_extends_or_decorators)
    }

