    pub(crate) fn get_symbol_handle(
        &mut self,
        symbols: &ast::SymbolHandleTable,
        name: &str,
        meaning: ast::SymbolFlags,
    ) -> Option<ast::SymbolHandle> {
        if !meaning.intersects(ast::SYMBOL_FLAGS_ALL) {
            return None;
        }
        let mut symbol = SymbolIdentity::from_symbol_handle(*symbols.get(name)?);
        symbol = self.get_merged_symbol_identity(Some(symbol)).unwrap();
        if self.symbol_identity_matches_meaning(symbol, meaning) {
            let symbol = symbol.symbol_handle();
            return Some(symbol);
        }
        None
    }

    pub(crate) fn merged_symbol_handle_matches_meaning(
        &mut self,
        symbol: ast::SymbolHandle,
        meaning: ast::SymbolFlags,
    ) -> Option<ast::SymbolHandle> {
        if !meaning.intersects(ast::SYMBOL_FLAGS_ALL) {
            return None;
        }
        let symbol = SymbolIdentity::from_symbol_handle(symbol);
        let symbol = self.get_merged_symbol_identity(Some(symbol)).unwrap();
        if self.symbol_identity_matches_meaning(symbol, meaning) {
            return Some(symbol.symbol_handle());
        }
        None
    }

    pub(crate) fn get_suggestion_for_symbol_handle_name_lookup(
        &mut self,
        symbols: &ast::SymbolHandleTable,
        name: &str,
        meaning: ast::SymbolFlags,
    ) -> Option<ast::SymbolHandle> {
        let symbol = self.get_symbol_handle(symbols, name, meaning);
        if symbol.is_some() {
            return symbol;
        }
        let mut candidates = symbols.values().copied().collect::<Vec<_>>();
        if meaning.intersects(ast::SYMBOL_FLAGS_GLOBAL_LOOKUP) {
            for &builtin_name in PRIMITIVE_TYPE_ALIAS_SUGGESTION_BUILTINS {
                if symbols.contains_key(builtin_name)
                    && let Some(suggestion) = self
                        .semantic_state
                        .primitive_type_alias_suggestion(builtin_name)
                {
                    candidates.push(suggestion);
                }
            }
        }
        self.get_spelling_suggestion_for_symbol_handle_name(name, candidates, meaning)
    }

    pub(crate) fn get_suggestion_for_node_local_name_lookup(
        &mut self,
        node: ast::Node,
        name: &str,
        meaning: ast::SymbolFlags,
    ) -> Option<ast::SymbolHandle> {
        if let Some(symbol) = self.lookup_node_local(node, name, meaning) {
            return Some(symbol);
        }
        let (mut candidates, primitive_builtins_present) =
            self.with_node_locals(node, |locals| {
                let mut primitive_builtins_present =
                    [false; PRIMITIVE_TYPE_ALIAS_SUGGESTION_BUILTINS.len()];
                for (index, builtin_name) in
                    PRIMITIVE_TYPE_ALIAS_SUGGESTION_BUILTINS.iter().enumerate()
                {
                    primitive_builtins_present[index] = locals.contains_key(*builtin_name);
                }
                (
                    locals.values().copied().collect::<Vec<_>>(),
                    primitive_builtins_present,
                )
            })?;
        self.add_primitive_type_alias_suggestion_candidates(
            meaning,
            primitive_builtins_present,
            &mut candidates,
        );
        self.get_spelling_suggestion_for_symbol_handle_name(name, candidates, meaning)
    }

    pub(crate) fn get_suggestion_for_symbol_handle_member_name_lookup(
        &mut self,
        symbol: ast::SymbolHandle,
        name: &str,
        meaning: ast::SymbolFlags,
    ) -> Option<ast::SymbolHandle> {
        if let Some(symbol) = self
            .lookup_symbol_handle_member(symbol, name)
            .filter(|symbol| self.symbol_handle_matches_meaning(*symbol, meaning))
        {
            return Some(symbol);
        }
        let Some((mut candidates, primitive_builtins_present)) =
            self.with_symbol_handle_members(symbol, |members| {
                members.map(|members| {
                    let mut primitive_builtins_present =
                        [false; PRIMITIVE_TYPE_ALIAS_SUGGESTION_BUILTINS.len()];
                    for (index, builtin_name) in
                        PRIMITIVE_TYPE_ALIAS_SUGGESTION_BUILTINS.iter().enumerate()
                    {
                        primitive_builtins_present[index] = members.contains_key(*builtin_name);
                    }
                    (
                        members.values().copied().collect::<Vec<_>>(),
                        primitive_builtins_present,
                    )
                })
            })
        else {
            return None;
        };
        self.add_primitive_type_alias_suggestion_candidates(
            meaning,
            primitive_builtins_present,
            &mut candidates,
        );
        self.get_spelling_suggestion_for_symbol_handle_name(name, candidates, meaning)
    }

    pub(crate) fn get_suggestion_for_symbol_handle_export_name_lookup(
        &mut self,
        symbol: ast::SymbolHandle,
        name: &str,
        meaning: ast::SymbolFlags,
    ) -> Option<ast::SymbolHandle> {
        if let Some(symbol) = self
            .lookup_symbol_handle_export(symbol, name)
            .filter(|symbol| self.symbol_handle_matches_meaning(*symbol, meaning))
        {
            return Some(symbol);
        }
        let Some((mut candidates, primitive_builtins_present)) =
            self.with_symbol_handle_exports(symbol, |exports| {
                exports.map(|exports| {
                    let mut primitive_builtins_present =
                        [false; PRIMITIVE_TYPE_ALIAS_SUGGESTION_BUILTINS.len()];
                    for (index, builtin_name) in
                        PRIMITIVE_TYPE_ALIAS_SUGGESTION_BUILTINS.iter().enumerate()
                    {
                        primitive_builtins_present[index] = exports.contains_key(*builtin_name);
                    }
                    let mut candidates = Vec::new();
                    exports.for_each_handle(|_, symbol| candidates.push(symbol));
                    (candidates, primitive_builtins_present)
                })
            })
        else {
            return None;
        };
        self.add_primitive_type_alias_suggestion_candidates(
            meaning,
            primitive_builtins_present,
            &mut candidates,
        );
        self.get_spelling_suggestion_for_symbol_handle_name(name, candidates, meaning)
    }

    fn add_primitive_type_alias_suggestion_candidates(
        &mut self,
        meaning: ast::SymbolFlags,
        primitive_builtins_present: [bool; PRIMITIVE_TYPE_ALIAS_SUGGESTION_BUILTINS.len()],
        candidates: &mut Vec<ast::SymbolHandle>,
    ) {
        if !meaning.intersects(ast::SYMBOL_FLAGS_GLOBAL_LOOKUP) {
            return;
        }
        for (index, &builtin_name) in PRIMITIVE_TYPE_ALIAS_SUGGESTION_BUILTINS.iter().enumerate() {
            if primitive_builtins_present[index]
                && let Some(suggestion) = self
                    .semantic_state
                    .primitive_type_alias_suggestion(builtin_name)
            {
                candidates.push(suggestion);
            }
        }
    }

    pub(crate) fn get_suggestion_for_global_symbol_handle_name_lookup(
        &mut self,
        name: &str,
        meaning: ast::SymbolFlags,
    ) -> Option<ast::SymbolHandle> {
        if let Some(symbol) = self.lookup_global_symbol_handle(name, meaning) {
            return Some(symbol);
        }
        let candidates = self.global_symbol_handle_candidates(meaning);
        self.get_spelling_suggestion_for_symbol_handle_name(name, candidates, meaning)
    }

    pub(crate) fn get_suggestion_for_symbol_identity_name_lookup(
        &mut self,
        symbols: &SymbolIdentityTable,
        name: &str,
        meaning: ast::SymbolFlags,
    ) -> Option<SymbolIdentity> {
        let symbol = self.get_symbol_identity_for_lookup(symbols, name, meaning);
        if symbol.is_some() {
            return symbol;
        }
        let mut candidates = symbols.values().copied().collect::<Vec<_>>();
        if meaning.intersects(ast::SYMBOL_FLAGS_GLOBAL_LOOKUP) {
            for &builtin_name in PRIMITIVE_TYPE_ALIAS_SUGGESTION_BUILTINS {
                if symbols.contains_key(builtin_name)
                    && let Some(suggestion) = self
                        .semantic_state
                        .primitive_type_alias_suggestion(builtin_name)
                {
                    candidates.push(SymbolIdentity::from_symbol_handle(suggestion));
                }
            }
        }
        self.get_spelling_suggestion_for_symbol_identity_name(name, candidates, meaning)
    }

    fn get_symbol_identity_for_lookup(
        &mut self,
        symbols: &SymbolIdentityTable,
        name: &str,
        meaning: ast::SymbolFlags,
    ) -> Option<SymbolIdentity> {
        if !meaning.intersects(ast::SYMBOL_FLAGS_ALL) {
            return None;
        }
        let symbol = self.get_merged_symbol_identity(symbols.get(name).copied())?;
        if self.symbol_identity_matches_meaning(symbol, meaning) {
            return Some(symbol);
        }
        None
    }

    fn get_spelling_suggestion_for_symbol_handle_name(
        &mut self,
        name: &str,
        symbols: impl IntoIterator<Item = ast::SymbolHandle>,
        meaning: ast::SymbolFlags,
    ) -> Option<ast::SymbolHandle> {
        let mut candidates = Vec::new();
        for symbol in symbols {
            let Some(candidate_flags) = self.symbol_handle_flags_if_resolved(symbol) else {
                continue;
            };
            let candidate_name = self.symbol_handle_name(symbol).to_string();
            if candidate_name.is_empty()
                || candidate_name.as_bytes()[0] == b'"'
                || candidate_name.starts_with(ast::INTERNAL_SYMBOL_NAME_PREFIX)
            {
                continue;
            }
            let matches = if candidate_flags.intersects(meaning) {
                true
            } else if candidate_flags.intersects(ast::SYMBOL_FLAGS_ALIAS) {
                self.try_resolve_alias(SymbolIdentity::from_symbol_handle(symbol))
                    .is_some_and(|alias| {
                        self.missing_name_symbol_identity_flags(alias)
                            .intersects(meaning)
                    })
            } else {
                false
            };
            if matches {
                candidates.push(Some((
                    SymbolIdentity::from_symbol_handle(symbol),
                    candidate_name,
                )));
            }
        }
        core::get_spelling_suggestion(
            name,
            candidates,
            |candidate| {
                candidate
                    .as_ref()
                    .map(|candidate| candidate.1.clone())
                    .unwrap_or_default()
            },
            |a, b| match (a.as_ref(), b.as_ref()) {
                (Some(a), Some(b)) => self.compare_symbol_identities_for_spelling(a.0, b.0),
                (None, Some(_)) => std::cmp::Ordering::Greater,
                (Some(_), None) => std::cmp::Ordering::Less,
                (None, None) => std::cmp::Ordering::Equal,
            },
        )
        .map(|candidate| candidate.0.symbol_handle())
    }

    fn get_spelling_suggestion_for_symbol_identity_name(
        &mut self,
        name: &str,
        symbols: impl IntoIterator<Item = SymbolIdentity>,
        meaning: ast::SymbolFlags,
    ) -> Option<SymbolIdentity> {
        let mut candidates = Vec::new();
        for symbol in symbols {
            let candidate_name = self.missing_name_symbol_identity_name(symbol);
            if candidate_name.is_empty()
                || candidate_name.as_bytes()[0] == b'"'
                || candidate_name.starts_with(ast::INTERNAL_SYMBOL_NAME_PREFIX)
            {
                continue;
            }
            if self.symbol_identity_matches_meaning(symbol, meaning) {
                candidates.push(Some((symbol, candidate_name)));
            }
        }
        core::get_spelling_suggestion(
            name,
            candidates,
            |candidate| {
                candidate
                    .as_ref()
                    .map(|candidate| candidate.1.clone())
                    .unwrap_or_default()
            },
            |a, b| match (a.as_ref(), b.as_ref()) {
                (Some(a), Some(b)) => self.compare_symbol_identities_for_spelling(a.0, b.0),
                (None, Some(_)) => std::cmp::Ordering::Greater,
                (Some(_), None) => std::cmp::Ordering::Less,
                (None, None) => std::cmp::Ordering::Equal,
            },
        )
        .map(|candidate| candidate.0)
    }

    fn compare_symbol_identities_for_spelling(
        &self,
        left: SymbolIdentity,
        right: SymbolIdentity,
    ) -> std::cmp::Ordering {
        if left == right {
            return std::cmp::Ordering::Equal;
        }
        let left_declaration = self.first_symbol_identity_declaration(left);
        let right_declaration = self.first_symbol_identity_declaration(right);
        if let (Some(left_declaration), Some(right_declaration)) =
            (left_declaration, right_declaration)
        {
            let order = self.compare_nodes_for_spelling(left_declaration, right_declaration);
            if order != std::cmp::Ordering::Equal {
                return order;
            }
        } else if left_declaration.is_some() {
            return std::cmp::Ordering::Less;
        } else if right_declaration.is_some() {
            return std::cmp::Ordering::Greater;
        }
        let order = self
            .missing_name_symbol_identity_name_ref(left)
            .cmp(self.missing_name_symbol_identity_name_ref(right));
        if order != std::cmp::Ordering::Equal {
            return order;
        }
        self.compare_symbol_identity_ids_for_spelling(left, right)
    }

    fn compare_nodes_for_spelling(&self, left: ast::Node, right: ast::Node) -> std::cmp::Ordering {
        if left == right {
            return std::cmp::Ordering::Equal;
        }
        let left_file = self.try_source_file_for_node_with_order(left);
        let right_file = self.try_source_file_for_node_with_order(right);
        let same_file = match (left_file, right_file) {
            (Some((_, left_index)), Some((_, right_index))) => left_index == right_index,
            (None, None) => true,
            _ => false,
        };
        if !same_file {
            let left_index = left_file.map(|(_, index)| index).unwrap_or(usize::MAX);
            let right_index = right_file.map(|(_, index)| index).unwrap_or(usize::MAX);
            return left_index.cmp(&right_index);
        }
        let left_store = left_file
            .map(|(file, _)| file.store())
            .unwrap_or_else(|| self.store_for_node(left));
        let right_store = right_file
            .map(|(file, _)| file.store())
            .unwrap_or_else(|| self.store_for_node(right));
        left_store
            .loc(left)
            .pos()
            .cmp(&right_store.loc(right).pos())
    }

    fn compare_symbol_identity_ids_for_spelling(
        &self,
        left: SymbolIdentity,
        right: SymbolIdentity,
    ) -> std::cmp::Ordering {
        self.compare_symbol_identity_tiebreaker(left, right)
    }

    pub(crate) fn compare_symbol_identity_tiebreaker(
        &self,
        left: SymbolIdentity,
        right: SymbolIdentity,
    ) -> std::cmp::Ordering {
        self.symbol_handle_id(left.symbol_handle())
            .cmp_for_ordering(self.symbol_handle_id(right.symbol_handle()))
    }

    pub(crate) fn compare_symbol_identities(
        &self,
        left: SymbolIdentity,
        right: SymbolIdentity,
    ) -> std::cmp::Ordering {
        if left == right {
            return std::cmp::Ordering::Equal;
        }
        let left_declaration = self.first_symbol_identity_declaration(left);
        let right_declaration = self.first_symbol_identity_declaration(right);
        match (left_declaration, right_declaration) {
            (Some(left_node), Some(right_node)) if left_node != right_node => {
                let order = self.compare_nodes_for_spelling(left_node, right_node);
                if order != std::cmp::Ordering::Equal {
                    return order;
                }
            }
            (Some(_), None) => return std::cmp::Ordering::Less,
            (None, Some(_)) => return std::cmp::Ordering::Greater,
            _ => {}
        }

        let name_order = self
            .symbol_identity_name_ref(left)
            .cmp(self.symbol_identity_name_ref(right));
        if name_order != std::cmp::Ordering::Equal {
            return name_order;
        }
        self.compare_symbol_identity_tiebreaker(left, right)
    }

    pub(crate) fn lookup_global_symbol_handle(
        &mut self,
        name: &str,
        meaning: ast::SymbolFlags,
    ) -> Option<ast::SymbolHandle> {
        if !meaning.intersects(ast::SYMBOL_FLAGS_ALL) {
            return None;
        }
        if let Some(symbol) = self
            .global_symbol_identity(name)
            .and_then(|symbol| self.get_merged_symbol_identity(Some(symbol)))
            && self.symbol_identity_matches_meaning(symbol, meaning)
        {
            return Some(symbol.symbol_handle());
        }
        None
    }

    fn global_symbol_handle_candidates(
        &mut self,
        meaning: ast::SymbolFlags,
    ) -> Vec<ast::SymbolHandle> {
        let mut candidates = Vec::new();
        candidates.extend(self.semantic_state.global_symbol_handles());
        if meaning.intersects(ast::SYMBOL_FLAGS_GLOBAL_LOOKUP) {
            for &builtin_name in PRIMITIVE_TYPE_ALIAS_SUGGESTION_BUILTINS {
                if self.has_global_symbol_handle_name(builtin_name)
                    && let Some(suggestion) = self
                        .semantic_state
                        .primitive_type_alias_suggestion(builtin_name)
                {
                    candidates.push(suggestion);
                }
            }
        }
        candidates
    }

