    pub(crate) fn resolve_symbol_identity(
        &mut self,
        symbol: SymbolIdentity,
        dont_resolve_alias: bool,
    ) -> SymbolIdentity {
        if dont_resolve_alias {
            return symbol;
        }
        let symbol_handle = symbol.symbol_handle();
        self.resolve_symbol_handle_identity(symbol_handle)
    }

    pub(crate) fn same_symbol_identity(
        &mut self,
        left: SymbolIdentity,
        right: SymbolIdentity,
    ) -> bool {
        if left == right {
            return true;
        }
        let left_resolved = self.resolve_symbol_identity(left, false);
        let left = self
            .get_merged_symbol_identity(Some(left_resolved))
            .unwrap_or(left);
        let right_resolved = self.resolve_symbol_identity(right, false);
        let right = self
            .get_merged_symbol_identity(Some(right_resolved))
            .unwrap_or(right);
        left == right
    }

    pub(crate) fn same_optional_symbol_identity(
        &mut self,
        left: Option<SymbolIdentity>,
        right: Option<SymbolIdentity>,
    ) -> bool {
        match (left, right) {
            (Some(left), Some(right)) => self.same_symbol_identity(left, right),
            (None, None) => true,
            _ => false,
        }
    }

    pub(crate) fn same_symbol_identity_ref(
        &self,
        left: &SymbolIdentity,
        right: &SymbolIdentity,
    ) -> bool {
        *left == *right
    }

    pub(crate) fn same_optional_symbol_identity_ref(
        &self,
        left: Option<&SymbolIdentity>,
        right: Option<&SymbolIdentity>,
    ) -> bool {
        match (left, right) {
            (Some(left), Some(right)) => self.same_symbol_identity_ref(left, right),
            (None, None) => true,
            _ => false,
        }
    }

