    pub(crate) fn report_unreliable_worker(&mut self, t: TypeHandle) -> TypeHandle {
        if t == self.semantic_state.semantic_handles().marker_super_type
            || t == self.semantic_state.semantic_handles().marker_sub_type
            || t == self.semantic_state.semantic_handles().marker_other_type
        {
            self.add_reliability_flags(RELATION_COMPARISON_RESULT_REPORTS_UNRELIABLE);
        }
        t
    }

