    pub(crate) fn new_conditional_type(
        &mut self,
        root: ConditionalRootHandle,
        mapper: Option<TypeMapperHandle>,
        combined_mapper: Option<TypeMapperHandle>,
    ) -> TypeHandle {
        let root_record = self.conditional_root_record(root).clone();
        let check_type = self.instantiate_type_with_mapper_handle(root_record.check_type, mapper);
        let extends_type =
            self.instantiate_type_with_mapper_handle(root_record.extends_type, mapper);
        self.new_type(
            TYPE_FLAGS_CONDITIONAL,
            OBJECT_FLAGS_NONE,
            TypeRecordData::Conditional(ConditionalTypeRecord {
                root: Some(root),
                check_type,
                extends_type,
                mapper,
                combined_mapper,
                ..Default::default()
            }),
        )
    }

