    pub(crate) fn new_signature(
        &mut self,
        flags: SignatureFlags,
        declaration: Option<ast::Node>,
        type_parameters: Vec<TypeHandle>,
        this_parameter: Option<SymbolIdentity>,
        parameters: Vec<SymbolIdentity>,
        resolved_return_type: Option<TypeHandle>,
        resolved_type_predicate: Option<TypePredicateHandle>,
        min_argument_count: i32,
    ) -> SignatureHandle {
        self.new_signature_from_parameter_list(
            flags,
            declaration,
            type_parameters,
            this_parameter,
            Arc::from(parameters),
            resolved_return_type,
            resolved_type_predicate,
            min_argument_count,
        )
    }

