    pub(crate) fn new_signature_from_parameter_list(
        &mut self,
        flags: SignatureFlags,
        declaration: Option<ast::Node>,
        type_parameters: Vec<TypeHandle>,
        this_parameter: Option<SymbolIdentity>,
        parameters: Arc<[SymbolIdentity]>,
        resolved_return_type: Option<TypeHandle>,
        resolved_type_predicate: Option<TypePredicateHandle>,
        min_argument_count: i32,
    ) -> SignatureHandle {
        self.semantic_state.alloc_signature(SignatureRecord {
            flags,
            min_argument_count,
            resolved_min_argument_count: -1,
            declaration,
            type_parameters,
            parameters,
            this_parameter,
            resolved_return_type,
            resolved_type_predicate,
            target: None,
            mapper: None,
            isolated_signature_type: None,
            composite: None,
        })
    }

